const r4Test1683: fhir4.OperationDefinition = {"resourceType":"OperationDefinition","id":"ActivityDefinition-apply","meta":{"lastUpdated":"2019-11-01T09:29:23.356+11:00"},"text":{"status":"generated","div":"<div xmlns=\"http://www.w3.org/1999/xhtml\">\n            <h2>Apply</h2>\n            <p>OPERATION: Apply</p>\n            <p>The official URL for this operation definition is: </p>\n            <pre>http://hl7.org/fhir/OperationDefinition/ActivityDefinition-apply</pre>\n            <div>\n              <p>The apply operation applies a definition in a specific context</p>\n\n            </div>\n            <p>URL: [base]/ActivityDefinition/$apply</p>\n            <p>URL: [base]/ActivityDefinition/[id]/$apply</p>\n            <p>Parameters</p>\n            <table class=\"grid\">\n              <tr>\n                <td>\n                  <b>Use</b>\n                </td>\n                <td>\n                  <b>Name</b>\n                </td>\n                <td>\n                  <b>Cardinality</b>\n                </td>\n                <td>\n                  <b>Type</b>\n                </td>\n                <td>\n                  <b>Binding</b>\n                </td>\n                <td>\n                  <b>Documentation</b>\n                </td>\n              </tr>\n              <tr>\n                <td>IN</td>\n                <td>activityDefinition</td>\n                <td>0..1</td>\n                <td>\n                  <a href=\"activitydefinition.html\">ActivityDefinition</a>\n                </td>\n                <td/>\n                <td>\n                  <div>\n                    <p>The activity definition to apply. If the operation is invoked on an instance, this parameter is not allowed. If the operation is invoked at the type level, this parameter is required</p>\n\n                  </div>\n                </td>\n              </tr>\n              <tr>\n                <td>IN</td>\n                <td>subject</td>\n                <td>1..*</td>\n                <td>\n                  <a href=\"datatypes.html#string\">string</a>\n                  <br/>(\n                  <a href=\"search.html#reference\">reference</a>)\n                </td>\n                <td/>\n                <td>\n                  <div>\n                    <p>The subject(s) that is/are the target of the activity definition to be applied. The subject may be a Patient, Practitioner, Organization, Location, Device, or Group. Subjects provided in this parameter will be resolved as the subject of the PlanDefinition based on the type of the subject. If multiple subjects of the same type are provided, the behavior is implementation-defined</p>\n\n                  </div>\n                </td>\n              </tr>\n              <tr>\n                <td>IN</td>\n                <td>encounter</td>\n                <td>0..1</td>\n                <td>\n                  <a href=\"datatypes.html#string\">string</a>\n                  <br/>(\n                  <a href=\"search.html#reference\">reference</a>)\n                </td>\n                <td/>\n                <td>\n                  <div>\n                    <p>The encounter in context, if any</p>\n\n                  </div>\n                </td>\n              </tr>\n              <tr>\n                <td>IN</td>\n                <td>practitioner</td>\n                <td>0..1</td>\n                <td>\n                  <a href=\"datatypes.html#string\">string</a>\n                  <br/>(\n                  <a href=\"search.html#reference\">reference</a>)\n                </td>\n                <td/>\n                <td>\n                  <div>\n                    <p>The practitioner in context</p>\n\n                  </div>\n                </td>\n              </tr>\n              <tr>\n                <td>IN</td>\n                <td>organization</td>\n                <td>0..1</td>\n                <td>\n                  <a href=\"datatypes.html#string\">string</a>\n                  <br/>(\n                  <a href=\"search.html#reference\">reference</a>)\n                </td>\n                <td/>\n                <td>\n                  <div>\n                    <p>The organization in context</p>\n\n                  </div>\n                </td>\n              </tr>\n              <tr>\n                <td>IN</td>\n                <td>userType</td>\n                <td>0..1</td>\n                <td>\n                  <a href=\"datatypes.html#CodeableConcept\">CodeableConcept</a>\n                </td>\n                <td/>\n                <td>\n                  <div>\n                    <p>The type of user initiating the request, e.g. patient, healthcare provider, or specific type of healthcare provider (physician, nurse, etc.)</p>\n\n                  </div>\n                </td>\n              </tr>\n              <tr>\n                <td>IN</td>\n                <td>userLanguage</td>\n                <td>0..1</td>\n                <td>\n                  <a href=\"datatypes.html#CodeableConcept\">CodeableConcept</a>\n                </td>\n                <td/>\n                <td>\n                  <div>\n                    <p>Preferred language of the person using the system</p>\n\n                  </div>\n                </td>\n              </tr>\n              <tr>\n                <td>IN</td>\n                <td>userTaskContext</td>\n                <td>0..1</td>\n                <td>\n                  <a href=\"datatypes.html#CodeableConcept\">CodeableConcept</a>\n                </td>\n                <td/>\n                <td>\n                  <div>\n                    <p>The task the system user is performing, e.g. laboratory results review, medication list review, etc. This information can be used to tailor decision support outputs, such as recommended information resources</p>\n\n                  </div>\n                </td>\n              </tr>\n              <tr>\n                <td>IN</td>\n                <td>setting</td>\n                <td>0..1</td>\n                <td>\n                  <a href=\"datatypes.html#CodeableConcept\">CodeableConcept</a>\n                </td>\n                <td/>\n                <td>\n                  <div>\n                    <p>The current setting of the request (inpatient, outpatient, etc.)</p>\n\n                  </div>\n                </td>\n              </tr>\n              <tr>\n                <td>IN</td>\n                <td>settingContext</td>\n                <td>0..1</td>\n                <td>\n                  <a href=\"datatypes.html#CodeableConcept\">CodeableConcept</a>\n                </td>\n                <td/>\n                <td>\n                  <div>\n                    <p>Additional detail about the setting of the request, if any</p>\n\n                  </div>\n                </td>\n              </tr>\n              <tr>\n                <td>OUT</td>\n                <td>return</td>\n                <td>1..1</td>\n                <td>Any</td>\n                <td/>\n                <td>\n                  <div>\n                    <p>The resource that is the result of applying the definition</p>\n\n                  </div>\n                </td>\n              </tr>\n            </table>\n            <div>\n              <p>The result of invoking this operation is a resource of the type specified by the activity definition, with all the definitions resolved as appropriate for the type of resource. Any dynamicValue elements will be evaluated (in the order in which they appear in the resource) and the results applied to the returned resource.  If the ActivityDefinition includes library references, those libraries will be available to the evaluated expressions. If those libraries have parameters, those parameters will be bound by name to the parameters given to the operation. In addition, parameters to the $apply operation are available within dynamicValue expressions as context variables, accessible by the name of the parameter, prefixed with a percent (%) symbol. For a more detailed description, refer to the ActivityDefinition resource</p>\n\n            </div>\n          </div>"},"extension":[{"url":"http://hl7.org/fhir/StructureDefinition/structuredefinition-fmm","valueInteger":2},{"url":"http://hl7.org/fhir/StructureDefinition/structuredefinition-standards-status","valueCode":"trial-use"}],"url":"http://hl7.org/fhir/OperationDefinition/ActivityDefinition-apply","version":"4.0.1","name":"Apply","status":"draft","kind":"operation","date":"2019-11-01T09:29:23+11:00","publisher":"HL7 (FHIR Project)","contact":[{"telecom":[{"system":"url","value":"http://hl7.org/fhir"},{"system":"email","value":"fhir@lists.hl7.org"}]}],"description":"The apply operation applies a definition in a specific context","code":"apply","comment":"The result of invoking this operation is a resource of the type specified by the activity definition, with all the definitions resolved as appropriate for the type of resource. Any dynamicValue elements will be evaluated (in the order in which they appear in the resource) and the results applied to the returned resource.  If the ActivityDefinition includes library references, those libraries will be available to the evaluated expressions. If those libraries have parameters, those parameters will be bound by name to the parameters given to the operation. In addition, parameters to the $apply operation are available within dynamicValue expressions as context variables, accessible by the name of the parameter, prefixed with a percent (%) symbol. For a more detailed description, refer to the ActivityDefinition resource","resource":["ActivityDefinition"],"system":false,"type":true,"instance":true,"parameter":[{"name":"activityDefinition","use":"in","min":0,"max":"1","documentation":"The activity definition to apply. If the operation is invoked on an instance, this parameter is not allowed. If the operation is invoked at the type level, this parameter is required","type":"ActivityDefinition"},{"name":"subject","use":"in","min":1,"max":"*","documentation":"The subject(s) that is/are the target of the activity definition to be applied. The subject may be a Patient, Practitioner, Organization, Location, Device, or Group. Subjects provided in this parameter will be resolved as the subject of the PlanDefinition based on the type of the subject. If multiple subjects of the same type are provided, the behavior is implementation-defined","type":"string","searchType":"reference"},{"name":"encounter","use":"in","min":0,"max":"1","documentation":"The encounter in context, if any","type":"string","searchType":"reference"},{"name":"practitioner","use":"in","min":0,"max":"1","documentation":"The practitioner in context","type":"string","searchType":"reference"},{"name":"organization","use":"in","min":0,"max":"1","documentation":"The organization in context","type":"string","searchType":"reference"},{"name":"userType","use":"in","min":0,"max":"1","documentation":"The type of user initiating the request, e.g. patient, healthcare provider, or specific type of healthcare provider (physician, nurse, etc.)","type":"CodeableConcept"},{"name":"userLanguage","use":"in","min":0,"max":"1","documentation":"Preferred language of the person using the system","type":"CodeableConcept"},{"name":"userTaskContext","use":"in","min":0,"max":"1","documentation":"The task the system user is performing, e.g. laboratory results review, medication list review, etc. This information can be used to tailor decision support outputs, such as recommended information resources","type":"CodeableConcept"},{"name":"setting","use":"in","min":0,"max":"1","documentation":"The current setting of the request (inpatient, outpatient, etc.)","type":"CodeableConcept"},{"name":"settingContext","use":"in","min":0,"max":"1","documentation":"Additional detail about the setting of the request, if any","type":"CodeableConcept"},{"name":"return","use":"out","min":1,"max":"1","documentation":"The resource that is the result of applying the definition","type":"Any"}]};

